ms, and stakeholders.", "addressCountryOnly": "Thailand", "addressWithCountry": "Hua Hin, Prachuap Khiri Khan, Thailand", "addressWithoutCountry": "Hua Hin, Prachuap Khiri Khan", "backgroundPic": "https://media.licdn.com/dms/image/v2/D4D16AQGgagRzl9gkTA/profile-displaybackgroundimage-shrink_200_800/profile-displaybackgroundimage-shrink_200_800/0/1680846855107?e=1778112000&v=beta&t=n-unYjcD0MhXBJpmUVupk9634ve3z9g6Ct2oUXQUZto", "companyIndustry": "Hospitality", "companyLinkedin": "https://www.linkedin.com/company/the-standard-hua-hin/", "companyName": "The Standard, Hua Hin", "companySize": "201-500", "companyWebsite": "https://www.standardhotels.com/hua-hin/properties/hua-hin", "connections": "25156", "currentJobDuration": "3 yrs 1 mo", "currentJobDurationInYrs": "3.08", "educations/0/period/endedOn/month": "0", "educations/0/period/endedOn/year": "1999", "educations/0/period/startedOn/month": "0", "educations/0/period/startedOn/year": "1998", "educations/0/subtitle": "Hotel Management, Hospitality Administration/Management", "educations/0/title": "The Australian International Hotel School", "educations/1/companyId": "18946", "educations/1/companyLink1": "https://www.linkedin.com/school/cornell-university/", "educations/1/companyUrn": "urn:li:fsd_company:18946", "educations/1/description": "Participated in 5 month Semester at Cornell exchange program with the Australian International Hotel School.", "educations/1/logo": "https://media.licdn.com/dms/image/v2/C560BAQE8SOXGRyv7LA/company-logo_200_200/company-logo_200_200/0/1631339899678?e=1778112000&v=beta&t=XPjCUEJfiykmO9iB6jyNhXz62khd4aFQab9vo0g8SmY", "educations/1/period/endedOn/month": "0", "educations/1/period/endedOn/year": "1999", "educations/1/period/startedOn/month": "0", "educations/1/period/startedOn/year": "1999", "educations/1/subtitle": "Hotel Management, Hospitality Administration/Management", "educations/1/title": "Cornell University", "educations/2/grade": "Distinction", "educations/2/period/endedOn/mon