soViewed/25/follower_count": "963", "peopleAlsoViewed/25/headline": "Senior Sales Manager at The Standard, Hua Hin", "peopleAlsoViewed/25/last_name": "Janchoom", "peopleAlsoViewed/25/premium": "false", "peopleAlsoViewed/25/profile_picture": "https://media.licdn.com/dms/image/v2/D5603AQFGHhTzf7i9Iw/profile-displayphoto-crop_800_800/B56ZuxJ.H2JAAI-/0/1768203741799?e=1778112000&v=beta&t=7MLDqRYlm6Pnyr-J_5zKnoDiKYPOOMpU1D-tzvdZsCc", "peopleAlsoViewed/25/public_identifier": "patchanipha-janchoom", "peopleAlsoViewed/25/url": "https://linkedin.com/in/ACoAADDvwtQBTms9DS1aehiHtnqSpCfGZRWeR64", "profilePic": "https://media.licdn.com/dms/image/v2/D5603AQFweidiyIiRWg/profile-displayphoto-crop_800_800/B56Zrdtv95LcAI-/0/1764656350025?e=1778112000&v=beta&t=WFoud_RAxYsRSWtIj6w7Y0QthKUgNi5mIPQ98d9uOrI", "profilePicHighQuality": "https://media.licdn.com/dms/image/v2/D5603AQFweidiyIiRWg/profile-displayphoto-crop_800_800/B56Zrdtv95LcAI-/0/1764656350025?e=1778112000&v=beta&t=WFoud_RAxYsRSWtIj6w7Y0QthKUgNi5mIPQ98d9uOrI", "publicIdentifier": "nathalie-cockayne-luxury-lifestyle-hotel-leader", "publications/0/publishing_date": "Nov 2020", "publications/0/source": "Hotelintel", "publications/0/title": "Hotelier of the Month", "publications/0/url": "https://hotelintel.co/hotelier-of-the-month-nathalie-cockayne/", "recommendations/0/context": "Nathalie was senior to Zeeshan but didn't manage Zeeshan directly", "recommendations/0/date": "July 12, 2023", "recommendations/0/description": "Zee is a talented, hardworking, compassionate, creative, organized, resilient young man with 'Can-Do' attitude. I had the pleasure of working with him closely during my tenure at Melia Desert Palm and we tackled the entire marketing and digital enhancement of the Hotel together, thinking out of the box of ways to support the hotel, drive business, create engagement and understand the market demographics and audience.  We were elevated to 5 star and then upgraded to a Melia Collection Hotel as a result of many of these efforts. \nZee's e-commerce experience and positive nature made him a favourite with the team and Corporate office.  Highly recommend Zee not only for his marketing expertise, but also for his guitar playing & DJ skills!", "recommendations/0/name": "Zeeshan Khan", "recommendations/0/subtitle": "Digital Marketing Manager Asia, Europe & Middle East - Rixos & ALL Inclusive Collection", "recommendations/0/url": "https://www.linkedin.com/in/zeeshan-khan-6ab71222/", "recommendations/0/urn": "urn:li:fsd_profile:ACoAAAS7lmMBQeWoHZ-JSdPLygkvOHfBQIZzmoI", "recommendations/1/context": "Nathalie managed Sethu directly", "recommendations/1/date": "December 18, 2020", "recommendations/1/description": "I highly recommend Sethu as a strong hands on leader in F&B. His communication skills and work ethic, alongside a friendly and resilient personality made his an asset to the team. He manages teams well, drives revenue whenever he can and has strong financial acumen. He is very organized and put clients at ease when handling VIPs and large complex events. ", "recommendations/1/name": "Sethu Pradeep", "recommendations/1/subtitle": "Food and Beverage Manager", "recommendations/1/url": "https://www.linkedin.com/in/sethu-pradeep-a47a691b/", "recommendations/1/urn": "urn:li:fsd_profile:ACoAAARAEJcBlaxZ0zxReiSc3_03jqByoVocnHM", "recommendations/2/context": "Nathalie managed Sabrina directly", "recommendations/2/date": "December 18, 2020", "recommendations/2/description": "I highly recommend Sabrina as a great asset to any organization.  She is a motivated, genuine, trustworthy, hard working individual with a incredible work ethic and huge heart. Her positivity and reliability made her a role model for a large team and Sabrina used her strong EQ and resilience to drive for result and increase service standards and revenues. Her attention to detail and quality focus made her a excellent leader within the Rooms Division team. ", "recommendations/2/name": "Sabrina Offe (she/her)", "recommendations/2/subtitle": "Customer Experience | Project Management | Operations | Hospitality & Wellness | FemTech, Women’s Health & Healthcare | DE&I | Working on things that matter.", "recommendations/2/url": "https://www.linkedin.com/in/sabrina-offe/", "recommendations/2/urn": "urn:li:fsd_profile:ACoAAARV5SQB4rz_leBmEV9TV53FD9O3AoMZPkU", "recommendations/3/context": "Nathalie managed FARES directly", "recommendations/3/date": "December 18, 2020", "recommendations/3/description": "I highly recommend Fares due to his exceptional guest focus, he has the ability to make people feel comfortable and charmed. His high EQ enables him to handle tough situations with ease and composure.  He has a strong drive for results and financial acumen, is organized and iinnovative and looks for opportunities to improve revenues at every opportunity. He is well respected by his peers and was a pleasure to work with. ", "recommendations/3/name": "FARES KARAM", "recommendations/3/subtitle": "Residences Manager Six Senses Courchevel", "recommendations/3/url": "https://www.linkedin.com/in/fareskaram1983/", "recommendations/3/urn": "urn:li:fsd_profile:ACoAAB3Pa3ABIVFKRWm-LgODrKR7oQ83KXRMsSM", "recommendations/4/context": "Nathalie worked with Osama on the same team", "recommendations/4/date": "April 25, 2019", "recommendations/4/description": "Osama and I were colleagues at the H Dubai for a period of 2 years, during his role as Director of Human Resources.  Working with Osama was a fortunate opportunity to me, as he has a talent to remain focused on success of the Hotel team, whilst making adjustments to the way we worked to ensure we improved the profitability of the organization.  A true Business Partner for the Hotel, his financial acumen and strategic mentality was an asset to the Hotel.   Osama is a reliable and dedicated HR professional who would be an asset to any type of corporation when Human Resources Management is a priority. ", "recommendations/4/name": "Osama Fathy", "recommendations/4/subtitle": "Managing Director at Modern Human Resources Management", "recommendations/4/url": "https://www.linkedin.com/in/osamafathy/", "recommendations/4/urn": "urn:li:fsd_profile:ACoAAAXJTI4BT5WmjSeY1WG3jgkaitOHBoaw5oM", "recommendations/5/context": "Nathalie managed Reza directly", "recommendations/5/date": "December 8, 2016", "recommendations/5/description": "Reza's talent in F&B lies with his passion for people, his eye for detail, his focus on training and pushing the team around him to stretch their limits and develop them to the next level.  His combination of both corporate & operational experience has placed him as a strong well rounded Hotelier. He has the ability to grow teams & concepts from scratch, or motivate & drive existing teams to success.  His friendly, charming nature makes his well liked by peers, colleagues and guests, and he never seems to tire of being hands on and out on the floor with his people. ", "recommendations/5/name": "Reza Kalantarian", "recommendations/5/subtitle": "VP Operations & Membership at Aethos Hotels | Strategic Leadership, Operational Excellence", "recommendations/5/url": "https://www.linkedin.com/in/reza-kalantarian-bb5a3031/", "recommendations/5/urn": "urn:li:fsd_profile:ACoAAAa8wbkBpZxzzg9Pf1Up_m6y6K3Ok9Z6cm4", "recommendations/6/context": "Nathalie worked with Rowen but they were at different companies", "recommendations/6/date": "January 26, 2016", "recommendations/6/description": "I had the great pleasure of working alongside Rowen during my time at The H Hotel, whilst he ran OKKU in both the capacity of General Manager and Director of Operations.  Our professional relationship is one I will remember with great fondness, as working with 3rd party operators within a hotel can sometimes be challenging, but Rowen proved to be an honourable, intelligent, creative, fair, business minded individual who always worked with his teams best interests at heart, and found an easy balance between his outlets needs and the hotel's expectations.  I would have no hesitation to recommend,  hire or work alongside Rowen again in the future.", "recommendations/6/name": "Rowen Elmes", "recommendations/6/subtitle": "Director of Operations I Luxury I Hotels I Restaurants I Nightlife I Events I Bars I Openings", "recommendations/6/url": "https://www.linkedin.com/in/rowen-elmes-aa859b67/", "recommendations/6/urn": "urn:li:fsd_profile:ACoAAA4llWABx_phEE5WRKTFD4qp7vAxY0ZRiX0", "recommendations/7/context": "Nathalie reported directly to Stefan", "recommendations/7/date": "November 8, 2012", "recommendations/7/description": "Stefan has been and will continue to be one of the most admirable Hoteliers I have had the pleasure of working for.  His never ending drive for results and passion for quality has inspired me over the years, and I am proud to be able to call him a mentor.  He is a truly professional hotelier and a fantastic leader.", "recommendations/7/name": "Stefan Soennichsen", "recommendations/7/subtitle": "Managing Director", "recommendations/7/url": "https://www.linkedin.com/in/stefan-soennichsen-72342513/", "recommendations/7/urn": "urn:li:fsd_profile:ACoAAAK7Z8sBJXnkuHk5_WT4uYjXHAIa0jBmrMk", "recommendations/8/context": "Nathalie reported directly to Florent", "recommendations/8/date": "November 8, 2012", "recommendations/8/description": "Working with Florent for the opening of The Setai was possibly one of the most challenging and rewarding experiences of my career.  His coaching, support and guidance over that period was invaluable, and I want to thank him for helping develop me to become the successful hotelier I am today.", "recommendations/8/name": "Florent Gateau", "recommendations/8/subtitle": "Hotelier - Advisor", "recommendations/8/url": "https://www.linkedin.com/in/florent-gateau-6aa2a45/", "recommendations/8/urn": "urn:li:fsd_profile:ACoAAADusOIBSjjvcyoEMnWAK6c10LkKf1_MlgM", "recommendations/9/context": "Nathalie was senior to Fernando but didn't manage Fernando directly", "recommendations/9/date": "November 8, 2012", "recommendations/9/description": "It was a pleasure to have Fernando join us as a trainee at the Island Shangri-La for 6 months.  He positive, hard working, eager to learn attitude made him well liked and respected by managers, peers and guests, and I believe he will be very successful in his future career.", "recommendations/9/name": "Fernando Bas Gil", "recommendations/9/subtitle": "Director of Rooms at The Peninsula Tokyo", "recommendations/9/url": "https://www.linkedin.com/in/fernandobasgil/", "recommendations/9/urn": "urn:li:fsd_profile:ACoAAAcd1kkBHjlECfiv0r1LSw-BId-IBClIWbU", "recommendations/10/context": "Nathalie managed Chris directly", "recommendations/10/date": "November 8, 2012", "recommendations/10/description": "Chris is a bright, loyal, quality driven, hard working manager who enjoys challenging the status quo, delighting guests and taking ownership of any task given to him.  It was a delight to see him promoted to AFOM and then quickly to FOM at Kowloon Shangri-La, and I am sure his success will continue throughout his future.", "recommendations/10/name": "Chris Lam", "recommendations/10/subtitle": "Resident Manager at The Luxe Manor", "recommendations/10/url": "https://www.linkedin.com/in/chris-lam-72a7514b/", "recommendations/10/urn": "urn:li:fsd_profile:ACoAAAqcY9IB9jBLCV01FWulBfX8zzuIBIA7hbI", "recommendations/11/context": "Nathalie was Lorraine's client", "recommendations/11/date": "September 29, 2012", "recommendations/11/description": "I hired Lorraine via Lycette & Associates to assist with the coverage of Maternity leave during the pre re-lauch period of The H Hotel.  Over a period of 3 months, Lorraine made an invaluable contribution to the Hotel, far exceeding our expectations in every possible way.  Her detailed expertise improved effieicency & productivity in both HSK & laundry.  Her connections in Dubai saved us money, time and effort on numerous occasions.  Her optimistic, driven, passionate, hard working, results focused personality made a strong, well trained, efficient workforce out of the HSK team, and I cannot thank her enough for the tremendous amount of work she put in to the project.  I would not hesitate to highly recommend Lorraine in the future.", "recommendations/11/name": "Lorraine Castelino", "recommendations/11/subtitle": "Director | Kangaroo Gifts Australia | Ethical Wholesale Gifts | Est. 1958", "recommendations/11/url": "https://www.linkedin.com/in/lorrainecastelino/", "recommendations/11/urn": "urn:li:fsd_profile:ACoAAADHI68BEN4mk_FZ9yTfVG2CLZ9VAcvUiIw", "recommendationsReceived/0/context": "Raafat reported directly to Nathalie", "recommendationsReceived/0/date": "December 2, 2022", "recommendationsReceived/0/description": "I highly recommend Nathalie for any high level role. She has what’s needed to get the job done. I worked with her for few years. Great leader to ask for advice and set up a process.", "recommendationsReceived/0/name": "Raafat Rohaiem", "recommendationsReceived/0/subtitle": "Hospitality Executive", "recommendationsReceived/0/url": "https://www.linkedin.com/in/raafat-rohaiem-2867955/", "recommendationsReceived/0/urn": "urn:li:fsd_profile:ACoAAAEBYEYBxak-eBVQwaDJE3d9X-3eEQK6hfU", "recommendationsReceived/1/context": "Joe worked with Nathalie but they were at different companies", "recommendationsReceived/1/date": "November 29, 2022", "recommendationsReceived/1/description": "I absolutely recommend Nathalie as an experienced, passionate hospitality professional. I’ve seen how she operates Meliá Desert Palm, and more importantly how she interacts with her team (and how her employees interact with her) - she has an outstanding rapport with her staff and it’s because she is grounded, down to earth and able to communicate with people on every level. She has exceptional attention to detail, and I found every experience I’ve had with her to make me like and respect her more and more. I really do wish Nathalie every success in her position, and any other position she may move to in the future. She’s an exceptional GM who will go very far.", "recommendationsReceived/1/name": "Joe Blackman MBE", "recommendationsReceived/1/subtitle": "Founder & Investor | Transatlantic Trade & Investment | Citizen Diplomacy Leader | Board & Executive Committee, Sister Cities International", "recommendationsReceived/1/url": "https://www.linkedin.com/in/blackmanjoe/", "recommendationsReceived/1/urn": "urn:li:fsd_profile:ACoAAAfPunYB715UXEWpI_M4AOyRc3E_mrziQuw", "recommendationsReceived/2/context": "FARES managed Nathalie directly", "recommendationsReceived/2/date": "October 27, 2022", "recommendationsReceived/2/description": "I had the chance to work with Nathalie in two different hotels. Her Professionalism and humanity approach are her biggest strengths.\n\nshe is active in recognising and acknowledging hard work and is mindful of rewarding top performers\n\nNathalie is a true leader who pulls you up and helps you to push your own boundaries. \n\nIt has been a privilege and real pleasure to work on a daily basis with her.", "recommendationsReceived/2/name": "FARES KARAM", "recommendationsReceived/2/subtitle": "Residences Manager Six Senses Courchevel", "recommendationsReceived/2/url": "https://www.linkedin.com/in/fareskaram1983/", "recommendationsReceived/2/urn": "urn:li:fsd_profile:ACoAAB3Pa3ABIVFKRWm-LgODrKR7oQ83KXRMsSM", "recommendationsReceived/3/context": "Sumesh reported directly to Nathalie", "recommendationsReceived/3/date": "June 4, 2019", "recommendationsReceived/3/description": "It was an absolute joy working with Nathalie and talking about inspirational leaders, she certainly tops my personal chart. Her operational expertise gives her a somewhat rare edge to finely balance guest experience with excellent revenue generation.  \nNathalie is very creative and a keen hotelier with a broad set of skills. She was instrumental in helping to bring about many improvements in service delivery, product upgrades, and was an important contributor to all of the successes we enjoyed as a team being the excellent leader and motivator she is. It was an absolute pleasure working with Nathalie and I wish her all the best in her future endeavors.\n", "recommendationsReceived/3/name": "Sumesh Nair", "recommendationsReceived/3/subtitle": "Hospitality Operations and Management", "recommendationsReceived/3/url": "https://www.linkedin.com/in/sumesh-nair-527ba512/", "recommendationsReceived/3/urn": "urn:li:fsd_profile:ACoAAAKq8q8BG3jG_jHr9_ViZ_kgZW_vSbq8w-M", "recommendationsReceived/4/context": "Reza reported directly to Nathalie", "recommendationsReceived/4/date": "May 26, 2019", "recommendationsReceived/4/description": "”I was impressed by Nathalie’s  ability to deal with even the toughest clients – effortlessly. I was always in awe of Nathalies ability to command a room and get people on board with ideas – even people who were initially on completely different pages.” She is true leader with a lot of passion and skill. A real professional operator!", "recommendationsReceived/4/name": "Reza Kalantarian", "recommendationsReceived/4/subtitle": "VP Operations & Membership at Aethos Hotels | Strategic Leadership, Operational Excellence", "recommendationsReceived/4/url": "https://www.linkedin.com/in/reza-kalantarian-bb5a3031/", "recommendationsReceived/4/urn": "urn:li:fsd_profile:ACoAAAa8wbkBpZxzzg9Pf1Up_m6y6K3Ok9Z6cm4", "recommendationsReceived/5/context": "Lars worked with Nathalie but they were at different companies", "recommendationsReceived/5/date": "August 25, 2014", "recommendationsReceived/5/description": "Nathalie Cockayne is manager of operations in the H-Hotel, where my restaurant is located. It doesn't take long to realize that she was the best person to turn to with all problems and situations.  If it was in her direct power she would waste no time to explain the situation and/or solve it.  If it was not her line of work, she could give you a contact within minutes.\nI really admired the realistic objective management side of her without loosing a warm approach towards business relations and guests.", "recommendationsReceived/5/name": "Lars Haesen", "recommendationsReceived/5/subtitle": "Founder Lars Haesen Redevelopment Projects - Founder Consil Private Venue", "recommendationsReceived/5/url": "https://www.linkedin.com/in/lars-haesen-03698a85/", "recommendationsReceived/5/urn": "urn:li:fsd_profile:ACoAABIex6oBWjKtIlAlvtZO0j4-nmJXYFQNK5A", "recommendationsReceived/6/context": "Peter worked with Nathalie on the same team", "recommendationsReceived/6/date": "August 24, 2014", "recommendationsReceived/6/description": "I worked with Nathalie during my consultancy period at The H Hotel. Her passion and drive for her product and have no limits. I am happy to say that she one of the most driven and loyal colleagues I have had the pleasure of working alongside.", "recommendationsReceived/6/name": "Peter Redding", "recommendationsReceived/6/subtitle": "Marketing Specialist at PRPR UAE", "recommendationsReceived/6/url": "https://www.linkedin.com/in/peter-redding-54319716/", "recommendationsReceived/6/urn": "urn:li:fsd_profile:ACoAAAM690MBFtnQrZtdO0xacSbywUWf0M_XgAo", "recommendationsReceived/7/context": "Amgad reported directly to Nathalie", "recommendationsReceived/7/date": "April 17, 2012", "recommendationsReceived/7/description": "One of the best manager I had work with.", "recommendationsReceived/7/name": "Amgad Michael", "recommendationsReceived/7/subtitle": "Business Centre Supervisor cum Police Reporter Supervisor at InterContinental Hotels Group", "recommendationsReceived/7/url": "https://www.linkedin.com/in/amgad-michael-a114585/", "recommendationsReceived/7/urn": "urn:li:fsd_profile:ACoAAAD00K0B4lspTpDGXaPoyn9lalBSksXU3ao", "recommendationsReceived/8/context": "Michael reported directly to Nathalie", "recommendationsReceived/8/date": "August 9, 2008", "recommendationsReceived/8/description": "Nathalie is an amazing, hardw